#include <stdio.h>
#define MAX_VELICINA 1001

void unesi(char niz[], int velicina) {
	char znak = getchar();
	if (znak == '\n') znak = getchar();
	int i = 0;
	while (i < velicina-1 && znak != '\n') {
		niz[i] = znak;
		i++;
		znak = getchar();
	}
	niz[i] = '\0';
}

int main()
{
    char tekst[MAX_VELICINA];
    char* p = tekst;
    int brojac = 0;

    printf("Unesite tekst (do 1000 karaktera): ");
    unesi(tekst, MAX_VELICINA);

	for (; *p != '\0'; p++) {
        if (*p == ' ' || *p == '.' || *p == ',' || *p == ';' || *p == ':' || *p == '!' || *p == '?' || *p == '-') {
            continue;
        }
        brojac++;
        if (brojac % 2 == 0) *p = '*';
    }

    printf("\nNovi string: %s", tekst);

    return 0;
}
